  1→import supabase from "./supabase.js";
  2→
  3→const FREEDOM_WALL_ITEM_TYPES = ["doodle", "sticker", "stamp", "note"];
  4→const REPORTABLE_ITEM_TYPES = ["doodle"];
  5→const DEFAULT_ITEMS_LIMIT = 200;
  6→const MAX_ITEMS_LIMIT = 400;
  7→const DEFAULT_WEEKS_LIMIT = 8;
  8→const MAX_WEEKS_LIMIT = 52;
  9→const NOTE_FONT_STYLES = ["normal", "bold", "italic"];
 10→const NOTE_FONT_FAMILIES = [
 11→    "Georgia",
 12→    "Courier New",
 13→    "Trebuchet MS",
 14→    "Arial",
 15→    "Times New Roman"
 16→];
 17→
 18→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 19→
 20→const parseLimit = (limit) => {
 21→    const parsedLimit = Number(limit ?? DEFAULT_ITEMS_LIMIT);
 22→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_ITEMS_LIMIT){
 23→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_ITEMS_LIMIT}`};
 24→    }
 25→    return Math.floor(parsedLimit);
 26→};
 27→
 28→const parseWeeksLimit = (limit) => {
 29→    const parsedLimit = Number(limit ?? DEFAULT_WEEKS_LIMIT);
 30→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_WEEKS_LIMIT){
 31→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_WEEKS_LIMIT}`};
 32→    }
 33→    return Math.floor(parsedLimit);
 34→};
 35→
 36→const parseTypeFilters = (types) => {
 37→    if(!types){
 38→        return [];
 39→    }
 40→
 41→    const parsedTypes = String(types)
 42→        .split(",")
 43→        .map((value) => value.trim().toLowerCase())
 44→        .filter(Boolean);
 45→
 46→    const uniqueTypes = [...new Set(parsedTypes)].filter((type) => FREEDOM_WALL_ITEM_TYPES.includes(type));
 47→    return uniqueTypes;
 48→};
 49→
 50→const parseColor = (value, fallback) => {
 51→    if(typeof value !== "string"){
 52→        return fallback;
 53→    }
 54→
 55→    const trimmed = value.trim();
 56→    if(!trimmed){
 57→        return fallback;
 58→    }
 59→
 60→    return trimmed;
 61→};
 62→
 63→const normalizeNumber = (value, fallback) => {
 64→    const parsedValue = Number(value);
 65→    if(Number.isNaN(parsedValue)){
 66→        return fallback;
 67→    }
 68→    return parsedValue;
 69→};
 70→
 71→const normalizePosition = (value, fallback) => clamp(normalizeNumber(value, fallback), 0, 1);
 72→
 73→const sanitizeDoodlePayload = (payload) => {
 74→    const points = Array.isArray(payload?.points)
 75→        ? payload.points
 76→            .map((point) => Number(point))
 77→            .filter((point) => !Number.isNaN(point))
 78→            .map((point) => clamp(point, 0, 1))
 79→        : [];
 80→
 81→    if(points.length < 4){
 82→        throw {status: 400, error: "doodle payload points must contain at least 2 coordinate pairs"};
 83→    }
 84→
 85→    const sanitizedPoints = points.length % 2 === 0
 86→        ? points
 87→        : points.slice(0, -1);
 88→
 89→    const normalizedSize = clamp(normalizeNumber(payload?.size, 2.8), 1, 24);
 90→    return {
 91→        points: sanitizedPoints,
 92→        color: parseColor(payload?.color, "#5f92ff"),
 93→        size: normalizedSize,
 94→        // Backward compatibility for older DB check constraints that still expect strokeWidth.
 95→        strokeWidth: normalizedSize
 96→    };
 97→};
 98→
 99→const sanitizeStickerPayload = (payload) => {
100→    const sticker = typeof payload?.sticker === "string" ? payload.sticker.trim() : "";
101→    const stickerId = typeof payload?.stickerId === "string" ? payload.stickerId.trim() : "";
102→    if(!sticker && !stickerId){
103→        throw {status: 400, error: "sticker payload requires sticker or stickerId"};
104→    }
105→
106→    const result = {
107→        x: normalizePosition(payload?.x, 0.5),
108→        y: normalizePosition(payload?.y, 0.5),
109→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.25, 6),
110→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
111→    };
112→
113→    if(sticker){
114→        result.sticker = sticker;
115→    } else {
116→        result.stickerId = stickerId;
117→    }
118→
119→    return result;
120→};
121→
122→const sanitizeStampPayload = (payload) => {
123→    const stamp = typeof payload?.stamp === "string" ? payload.stamp.trim() : "";
124→    if(!stamp){
125→        throw {status: 400, error: "stamp payload requires stamp"};
126→    }
127→
128→    return {
129→        stamp: stamp,
130→        x: normalizePosition(payload?.x, 0.5),
131→        y: normalizePosition(payload?.y, 0.5),
132→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.35, 5),
133→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
134→    };
135→};
136→
137→const sanitizeNotePayload = (payload) => {
138→    const text = typeof payload?.text === "string" ? payload.text.trim() : "";
139→    if(!text){
140→        throw {status: 400, error: "note payload requires text"};
141→    }
142→
143→    const requestedFontFamily = typeof payload?.fontFamily === "string" ? payload.fontFamily.trim() : "";
144→    const requestedFontStyle = typeof payload?.fontStyle === "string" ? payload.fontStyle.trim().toLowerCase() : "";
145→
146→    return {
147→        text: text.slice(0, 800),
148→        x: normalizePosition(payload?.x, 0.45),
149→        y: normalizePosition(payload?.y, 0.45),
150→        width: clamp(normalizeNumber(payload?.width, 0.26), 0.12, 0.9),
151→        height: clamp(normalizeNumber(payload?.height, 0.2), 0.1, 0.8),
152→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360),
153→        fontFamily: NOTE_FONT_FAMILIES.includes(requestedFontFamily) ? requestedFontFamily : "Arial",
154→        fontStyle: NOTE_FONT_STYLES.includes(requestedFontStyle) ? requestedFontStyle : "normal",
155→        fontColor: parseColor(payload?.fontColor, "#1f2937"),
156→        bgColor: parseColor(payload?.bgColor, "#fff4a8"),
157→        fontSize: clamp(normalizeNumber(payload?.fontSize, 16), 10, 64)
158→    };
159→};
160→
161→const sanitizePayloadByType = (itemType, payload) => {
162→    if(!payload || typeof payload !== "object" || Array.isArray(payload)){
163→        throw {status: 400, error: "payload should be an object"};
164→    }
165→
166→    if(itemType === "doodle"){
167→        return sanitizeDoodlePayload(payload);
168→    }
169→    if(itemType === "sticker"){
170→        return sanitizeStickerPayload(payload);
171→    }
172→    if(itemType === "stamp"){
173→        return sanitizeStampPayload(payload);
174→    }
175→    if(itemType === "note"){
176→        return sanitizeNotePayload(payload);
177→    }
178→
179→    throw {status: 400, error: "invalid freedom wall item type"};
180→};
