201→const assertActiveWeek = async(weekId) => {
202→    const {data: week, error: weekError} = await supabase
203→        .from("freedom_wall_weeks")
204→        .select("id, week_start, week_end, status")
205→        .eq("id", weekId)
206→        .maybeSingle();
207→
208→    if(weekError){
209→        console.error("supabase error while reading freedom wall week:", weekError.message);
210→        throw {status: 500, error: "failed to read freedom wall week"};
211→    }
212→
213→    if(!week?.id){
214→        throw {status: 404, error: "freedom wall week not found"};
215→    }
216→
217→    const nowIso = new Date().toISOString();
218→    if(week.status !== "active" || nowIso < week.week_start || nowIso >= week.week_end){
219→        throw {status: 409, error: "freedom wall week is not active"};
220→    }
221→
222→    return week;
223→};
