240→        .from("freedom_wall_weeks")
241→        .select("*")
242→        .eq("status", "active")
243→        .order("week_start", {ascending: false})
244→        .limit(1)
245→        .maybeSingle();
246→
247→    if(activeWeekError){
248→        console.error("supabase error while reading active freedom wall week:", activeWeekError.message);
249→        throw {status: 500, error: "failed to fetch active freedom wall week"};
