252→    if(!activeWeek){
253→        const {error: rotateError} = await supabase.rpc("rotate_freedom_wall_week");
254→        if(rotateError){
255→            console.error("rotate_freedom_wall_week rpc error:", rotateError.message);
256→        }
257→
258→        const retry = await supabase
259→            .from("freedom_wall_weeks")
260→            .select("*")
261→            .eq("status", "active")
262→            .order("week_start", {ascending: false})
263→            .limit(1)
264→            .maybeSingle();
265→
266→        activeWeek = retry.data;
267→        activeWeekError = retry.error;
268→    }
269→
270→    if(activeWeekError){
