345→export const createFreedomWallItemService = async({weekId, itemType, payload, zIndex = 0, userId}) => {
346→    if(!userId){
347→        throw {status: 401, error: "not authorized"};
348→    }
349→
350→    if(!weekId){
351→        throw {status: 400, error: "weekId is required"};
352→    }
