354→    const normalizedType = typeof itemType === "string" ? itemType.trim().toLowerCase() : "";
355→    if(!FREEDOM_WALL_ITEM_TYPES.includes(normalizedType)){
356→        throw {status: 400, error: "invalid freedom wall item type"};
