384→export const updateFreedomWallItemService = async({itemId, payload, zIndex, userId}) => {
385→    if(!userId){
386→        throw {status: 401, error: "not authorized"};
387→    }
388→
389→    if(!itemId){
390→        throw {status: 400, error: "itemId is required"};
391→    }
392→
393→    if(payload === undefined && zIndex === undefined){
394→        throw {status: 400, error: "payload or zIndex is required"};
395→    }
396→
397→    const {data: existingItem, error: existingItemError} = await supabase
398→        .from("freedom_wall_items")
399→        .select("id, week_id, user_id, item_type, payload, z_index")
400→        .eq("id", itemId)
401→        .is("deleted_at", null)
402→        .maybeSingle();
403→
404→    if(existingItemError){
405→        console.error("supabase error while reading freedom wall item:", existingItemError.message);
406→        throw {status: 500, error: "failed to read freedom wall item"};
407→    }
408→
409→    if(!existingItem?.id){
410→        throw {status: 404, error: "freedom wall item not found"};
411→    }
412→
413→    if(String(existingItem.user_id) !== String(userId)){
414→        throw {status: 403, error: "not allowed to edit this freedom wall item"};
415→    }
416→
417→    await assertActiveWeek(existingItem.week_id);
418→
419→    const updatePayload = {};
420→    if(payload !== undefined){
421→        const mergedPayload = {
422→            ...(existingItem.payload || {}),
423→            ...(payload || {})
424→        };
425→        updatePayload.payload = sanitizePayloadByType(existingItem.item_type, mergedPayload);
426→    }
427→
428→    if(zIndex !== undefined){
429→        updatePayload.z_index = clamp(normalizeNumber(zIndex, existingItem.z_index || 0), -100000, 100000);
430→    }
431→
432→    const {data: updatedItem, error: updateError} = await supabase
433→        .from("freedom_wall_items")
434→        .update(updatePayload)
435→        .eq("id", itemId)
436→        .select(selectItemColumns)
437→        .single();
438→
439→    if(updateError){
440→        console.error("supabase error while updating freedom wall item:", updateError.message);
441→        throwMappedDatabaseError(updateError, "failed to update freedom wall item");
442→    }
443→
444→    return {item: updatedItem};
445→};
